import{_ as e,o as t,c as o,e as i}from"./app-58c21a21.js";const d="/assets/react生命周期-156d79f2.jpg",l={},n=i('<h3 id="生命周期" tabindex="-1"><a class="header-anchor" href="#生命周期" aria-hidden="true">#</a> 生命周期</h3><p><code>React</code>生命周期分为三个阶段：<strong>挂载时（也叫实例化期）</strong>、<strong>更新时（也叫存在期）</strong>、<strong>卸载时（也叫销毁期）</strong>。 <img src="'+d+'"></p><h4 id="挂载期" tabindex="-1"><a class="header-anchor" href="#挂载期" aria-hidden="true">#</a> 挂载期</h4><p>当组件实例被创建并插入<code>DOM</code>时，其生命周期调用顺序如下：</p><ul><li>constructor() <ul><li>初始化</li></ul></li><li>static getDerivedStateFromProps()</li><li>render() <ul><li>渲染到页面：即组件的效果完全展示到页面上的过程，即<code>React</code>组件的<code>render</code>生命周期钩子。</li></ul></li><li>componentDidMount() <ul><li>挂载到页面后：即组件的效果在页面中展示完毕后，在<code>React</code>中是<code>componentDidMount</code>生命周期钩子。</li></ul></li></ul><h4 id="更新期" tabindex="-1"><a class="header-anchor" href="#更新期" aria-hidden="true">#</a> 更新期</h4><p>当组件的<code>props</code>或<code>state</code>发生变化时会触发更新。这个阶段主要有以下几个步骤：</p><ul><li>getDerivedStateFromProps()</li><li>shouldComponentUpdate() <ul><li>组件是否应该更新，这个生命周期钩子像是一个阀门，它返回一个布尔值，<code>true</code>为打开阀门，允许组件更新，<code>false</code>为关闭阀门，不允许组价更新。</li></ul></li><li>componentWillUpdate() <ul><li>组件将要更新，调用<code>forceUpdate</code>方法能够直接从该流程开始，越过了”阀门“，有强制更新组件的意思。</li></ul></li><li>render() <ul><li>将新的组件渲染到页面上的过程。</li></ul></li><li>componentDidUpdate() <ul><li>组件更新完毕后。</li></ul></li></ul><h4 id="卸载期" tabindex="-1"><a class="header-anchor" href="#卸载期" aria-hidden="true">#</a> 卸载期</h4><p>组件在使用完后被销毁的过程。这个阶段主要有以下几个步骤：</p><ul><li>componentWillUnmount()</li></ul><h3 id="总结" tabindex="-1"><a class="header-anchor" href="#总结" aria-hidden="true">#</a> 总结</h3><p>在每个周期中，<code>React</code>都提供了一些钩子函数，可以在这些函数中执行特定的操作。整体上感觉和<code>Vue</code>的生命周期查不多。 每个阶段的钩子函数，主要是用到的有：</p><ul><li>mount阶段：construtor-&gt;render-&gt;componentDidMount</li><li>update阶段：当setState,props变化时候，触发update阶段。经历sholdComponentUpdate[return true]-&gt;render-&gt;getSnapshotBeforUpdate[记录变更之前转台]-&gt;componentDidUpdate[有preState,preProps,snapshot参数]</li><li>unmount阶段：componentDidUnmount</li></ul>',14),a=[n];function r(c,s){return t(),o("div",null,a)}const p=e(l,[["render",r],["__file","Reactshengmingzhouqi.html.vue"]]);export{p as default};
